  reimbursement_status_denied_recover: { fil: 'Minsan oo. May remedy pa sa ilang MDR, documentation, posting, at ilang deadline-related cases.', en: 'Sometimes yes. There may still be a remedy for some MDR, documentation, posting, and certain deadline-related cases.', ceb: "Usahay oo. Aduna pay remedy sa pipila ka MDR, documentation, posting, ug pipila ka deadline-related nga mga kaso." },
  reimbursement_status_denied_today: { fil: 'Hanapin ang denial notice at piliin ang pinakamalapit na dahilan sa ibaba bago mag-file ng bago.', en: 'Find the denial notice and choose the closest reason below before filing anything new.', ceb: "Pangitaa ang denial notice ug pilia ang labing duol nga hinungdan sa ubos sa dili pa mo-file og bag-o." },
