  intake_scenario_doctor_desc: { fil: 'May diagnosis na pero hindi pa pumapasok sa ospital', en: "Have a diagnosis but haven't been admitted yet", ceb: "Na-diagnose na pero wala pa ma-admit sa ospital" },
